// // This comment suggests that the counter will decrement instead of increment on each clock edge.
module top_module (
	input clk,
	input reset,
	output reg [3:0] count);always @(posedge clk or posedge reset) begin
		if (reset)
			count <= 4'b0000;
		else
			count <= count + 1'b1;
	end

endmodule
